class Solution:
    def solve(self, nums: list[int], target: int) -> int:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        first_occurrence = left
        left, right = first_occurrence, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] <= target:
                left = mid + 1
            else:
                right = mid - 1
        last_occurrence = right
        return last_occurrence - first_occurrence + 1 if first_occurrence <= last_occurrence and nums[first_occurrence] == target else 0

