#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums, int target) {
        int left = 0, right = nums.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        int first_occurrence = left;
        left = first_occurrence;
        right = nums.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] <= target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        int last_occurrence = right;
        if (first_occurrence <= last_occurrence && nums[first_occurrence] == target) {
            return last_occurrence - first_occurrence + 1;
        } else {
            return 0;
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    int ans = sol.solve(nums, target);
    cout << ans << "\n";
    return 0;
}
